(In reply to Mark Millard from comment #37)

I got the lack-of-message evidence wrong: the
message would only show up for debug output
enabled contexts.

So here is the other place where EFI_ALREADY_STARTED
ends up being introduced:

efi_status_t EFIAPI efi_install_multiple_protocol_interfaces
                                (efi_handle_t *handle, ...)
{
        EFI_ENTRY("%p", handle);

        efi_va_list argptr;
        const efi_guid_t *protocol;
        void *protocol_interface;
        efi_handle_t old_handle;
        efi_status_t r = EFI_SUCCESS;
        int i = 0;

        if (!handle)
                return EFI_EXIT(EFI_INVALID_PARAMETER);

        efi_va_start(argptr, handle);
        for (;;) {
                protocol = efi_va_arg(argptr, efi_guid_t*);
                if (!protocol)
                        break;
                protocol_interface = efi_va_arg(argptr, void*);
                /* Check that a device path has not been installed before */
                if (!guidcmp(protocol, &efi_guid_device_path)) {
                        struct efi_device_path *dp = protocol_interface;

                        r = EFI_CALL(efi_locate_device_path(protocol, &dp,
                                                            &old_handle));
                        if (r == EFI_SUCCESS &&
                            dp->type == DEVICE_PATH_TYPE_END) {
                                EFI_PRINT("Path %pD already installed\n",
                                          protocol_interface);
                                r = EFI_ALREADY_STARTED;
                                break;
                        }
                }
